class Solution {
    findSequences(beginWord, endWord, wordList) {
        /**
         * Finds all the shortest transformation sequences from beginWord to endWord.
         */
        const wordSet = new Set(wordList); // Fast lookup and removal
        const queue = [[beginWord]]; // Each element is a path (array of words)
        const usedOnLevel = [beginWord];
        let level = 0;
        const ans = [];

        while (queue.length > 0) {
            const path = queue.shift();

            // Remove used words when moving to the next level
            if (path.length > level) {
                level++;
                for (let word of usedOnLevel) {
                    wordSet.delete(word);
                }
            }

            const word = path[path.length - 1];

            // If we found the target word
            if (word === endWord) {
                if (ans.length === 0) {
                    ans.push([...path]);
                } else if (ans[0].length === path.length) {
                    ans.push([...path]);
                }
            }

            // Try changing each character of the current word
            for (let i = 0; i < word.length; i++) {
                for (let c = 97; c <= 122; c++) { // 'a' to 'z'
                    const newWord = word.slice(0, i) + String.fromCharCode(c) + word.slice(i + 1);

                    if (wordSet.has(newWord)) {
                        path.push(newWord);
                        queue.push([...path]);
                        usedOnLevel.push(newWord);
                        path.pop();
                    }
                }
            }
        }

        return ans;
    }
}

